/// Try to verify GitHub artifact attestations. Returns:
/// - Ok(true) if attestations exist and verified successfully
/// - Ok(false) if attestations exist but verification failed
/// - Err(NoAttestations) if no attestations found
/// - Err(Error) if an error occurred during verification
async fn try_verify_github_attestations(
    &self,
    ctx: &InstallContext,
    tv: &ToolVersion,
    file_path: &std::path::Path,
    api_url: &str,
) -> std::result::Result<bool, VerificationStatus> {
    ctx.pr
        .set_message("verify GitHub artifact attestations".to_string());

    // Parse owner/repo from the repo string
    let repo = self.repo();
    let parts: Vec<&str> = repo.split('/').collect();
    if parts.len() != 2 {
        return Err(VerificationStatus::Error(format!(
            "Invalid repo format: {repo}"
        )));
    }
    let (owner, repo_name) = (parts[0], parts[1]);

    match crate::github::sigstore::verify_attestation(
        file_path,
        owner,
        repo_name,
        None, // We don't know the expected workflow
        Some(api_url),
    )
    .await
    {
        Ok(verified) => {
            if verified {
                ctx.pr
                    .set_message("✓ GitHub artifact attestations verified".to_string());
                debug!("GitHub artifact attestations verified successfully for {tv}");
            }
            Ok(verified)
        }
        Err(crate::github::sigstore::AttestationError::NoAttestations) => {
            // Archive-level attestations not found — some releases provide
            // per-file attestations instead of archive-level ones. Fall back
            // to extracting the archive and verifying each extracted file
            // individually. This is a security fallback: if per-file
            // verification finds valid attestations, we accept them; if it
            // fails, we return a hard error rather than silently accepting
            // unverified content.
            match self
                .try_verify_per_file_attachments(ctx, tv, file_path, owner, repo_name, api_url)
                .await
            {
                Ok(true) => {
                    ctx.pr
                        .set_message("✓ GitHub artifact attestations verified (per-file)".to_string());
                    debug!(
                        "Per-file GitHub artifact attestations verified successfully for {tv}"
                    );
                    Ok(true)
                }
                Ok(false) => {
                    // Per-file verification ran but no attested files found.
                    // This is equivalent to NoAttestations — the caller may
                    // try other provenance mechanisms.
                    Err(VerificationStatus::NoAttestations)
                }
                Err(crate::github::sigstore::AttestationError::NoAttestations) => {
                    // All extracted files have no attestations — same as
                    // archive NoAttestations.
                    Err(VerificationStatus::NoAttestations)
                }
                Err(e) => Err(VerificationStatus::Error(format!(
                    "per-file attestation verification failed: {e}"
                ))),
            }
        }
        Err(e) => Err(VerificationStatus::Error(e.to_string())),
    }
}

/// Extract an archive and verify each file individually against GitHub
/// artifact attestations.
///
/// This is a fallback used when archive-level GitHub artifact attestations
/// are unavailable but per-file attestations were published instead. Some
/// GitHub releases provide attestations for individual files inside an
/// archive rather than for the archive blob itself.
///
/// Returns:
/// - Ok(true) if at least one file was successfully verified
/// - Ok(false) if extraction succeeded but no attested files were found
/// - Err(NoAttestations) if extraction failed (non-archive file)
/// - Err(Verification) if any verified file failed cryptographic check
async fn try_verify_per_file_attachments(
    &self,
    ctx: &InstallContext,
    tv: &ToolVersion,
    archive_path: &std::path::Path,
    owner: &str,
    repo_name: &str,
    api_url: &str,
) -> std::result::Result<bool, crate::github::sigstore::AttestationError> {
    let format = file::TarFormat::from_file_name(
        archive_path.file_name().unwrap_or_default().to_string_lossy().as_ref(),
    );

    // If the file isn't an archive, there's nothing to extract for per-file
    // verification. Return NoAttestations to let the caller try other paths.
    if !format.is_archive() {
        return Err(crate::github::sigstore::AttestationError::NoAttestations);
    }

    let extract_dir = std::env::temp_dir().join(format!(
        "mise-per-file-attestation-{}",
        uuid::Uuid::new_v4()
    ));
    file::create_dir_all(&extract_dir)?;

    let opts = file::TarOptions::new(format);
    if let Err(e) = file::untar(archive_path, &extract_dir, &opts) {
        debug!(
            "failed to extract for per-file verification: {e}, skipping per-file fallback"
        );
        return Err(crate::github::sigstore::AttestationError::NoAttestations);
    }

    ctx.pr
        .set_message("verify per-file GitHub artifact attestations".to_string());

    // Collect all files recursively under the extraction directory
    let mut files: Vec<std::path::PathBuf> = Vec::new();
    collect_files(&extract_dir, &mut files)?;

    let mut verified_count = 0usize;

    for file in &files {
        // Skip metadata files — these are typically not attested and are not
        // security-critical (they don't affect the installed tool's behavior).
        let file_tree_path = file.strip_prefix(&extract_dir)?;
        let file_tree_str = file_tree_path.to_string_lossy();
        if is_metadata_file(&file_tree_str) {
            continue;
        }

        // Try to verify attestation for this file
        match crate::github::sigstore::verify_attestation(
            file,
            owner,
            repo_name,
            None,
            Some(api_url),
        )
        .await
        {
            Ok(true) => verified_count += 1,
            Ok(false) => {
                // This file has attestations but they don't verify — hard error.
                // We found attestations for this artifact but the cryptographic
                // chain didn't hold, indicating possible tampering or a version
                // mismatch. Fail closed.
                return Err(crate::github::sigstore::AttestationError::Verification(
                    format!(
                        "attestation verification failed for file: {}",
                        file_tree_str
                    ),
                ));
            }
            Err(crate::github::sigstore::AttestationError::NoAttestations) => {
                // No attestation found for this file. This can happen for
                // metadata files or files the release author didn't explicitly
                // attest. Not an error — we continue checking other files.
                trace!("no attestation for file: {}", file_tree_str);
            }
            Err(e) => {
                // Non-no-attestation error during per-file verification.
                // Treat as a hard verification error.
                return Err(e);
            }
        }
    }

    if verified_count > 0 {
        debug!(
            "per-file attestation: {} files verified for {tv}",
            verified_count
        );
        Ok(true)
    } else {
        debug!("per-file attestation: no attested files found");
        Ok(false)
    }
}

/// Recursively collect all file paths under `dir`.
fn collect_files(dir: &std::path::Path, files: &mut Vec<std::path::PathBuf>) -> Result<()> {
    if !dir.is_dir() {
        return Ok(());
    }
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            Self::collect_files(&path, files)?;
        } else {
            files.push(path);
        }
    }
    Ok(())
}

/// Return true if `path` refers to a common metadata file that is typically
/// not attested and not security-critical.
fn is_metadata_file(path: &str) -> bool {
    let path_lower = path.to_lowercase();
    let basename = path_lower.rsplit('/').next().unwrap_or(&path_lower);

    // Exact basename matches
    metadata_basename_prefix(basename, &[
        "readme", "license", "changelog", "contributing",
        "code_of_conduct", "codeofconduct", "security",
        "patents", "notice", "authors", "release_notes",
        "release-notes",
    ]) || basename.starts_with(".gitkeep") || basename.starts_with(".npmignore")
}

/// Check if `basename` starts with any of the given prefixes.
fn metadata_basename_prefix<'a>(
    basename: &str,
    prefixes: &'a [&'a str],
) -> bool {
    prefixes
        .iter()
        .any(|p| basename.starts_with(p) && (basename.len() == p.len() || !basename[p.len()..].chars().next().map_or(false, |c| c.is_alphanumeric() && c != '-')))
}

