+                // metadata files or files the release author didn't explicitly
+                // attest. Not an error — we continue checking other files.
+                trace!("no attestation for file: {}", file_tree_str);
+            }
+            Err(e) => {
+                // Non-no-attestation error during per-file verification.
+                // Treat as a hard verification error.
+                return Err(e);
+            }
+        }
+    }
