/// Return true if `path` refers to a common metadata file that is typically
/// not attested and not security-critical.
fn is_metadata_file(path: &str) -> bool {
    let path_lower = path.to_lowercase();
    let basename = path_lower.rsplit('/').next().unwrap_or(&path_lower);

    // Exact basename matches
    metadata_basename_prefix(basename, &[
        "readme", "license", "changelog", "contributing",
        "code_of_conduct", "codeofconduct", "security",
        "patents", "notice", "authors", "release_notes",
        "release-notes",
    ]) || basename.starts_with(".gitkeep") || basename.starts_with(".npmignore")
}

/// Check if `basename` starts with any of the given prefixes.
fn metadata_basename_prefix<'a>(
    basename: &str,
    prefixes: &'a [&'a str],
) -> bool {
    prefixes
        .iter()
        .any(|p| basename.starts_with(p) && (basename.len() == p.len() || !basename[p.len()..].chars().next().map_or(false, |c| c.is_alphanumeric() && c != '-')))
}

