    fn test_collect_files_collects_all_files_recursively() {
        // Use tempfile to create a real directory tree for testing
        let tmpdir = tempfile::tempdir().unwrap();
        let base = tmpdir.path();

        // Create a real directory structure
        file::create_dir_all(base.join("subdir1")).unwrap();
        file::create_dir_all(base.join("subdir1/deeper")).unwrap();
        file::write(base.join("file1.txt"), "a").unwrap();
        file::write(base.join("subdir1/file2.txt"), "b").unwrap();
        file::write(base.join("subdir1/deeper/file3.txt"), "c").unwrap();

        let mut files: Vec<std::path::PathBuf> = Vec::new();
        UnifiedGitBackend::collect_files(base, &mut files).unwrap();

        // Should find all 3 files
        assert_eq!(files.len(), 3, "expected 3 files, found {}", files.len());

        // Verify all files are present
        let names: std::collections::BTreeSet<String> =
            files.into_iter().map(|f| f.file_name().unwrap().to_string_lossy().into()).collect();
        assert!(names.contains("file1.txt"));
        assert!(names.contains("file2.txt"));
        assert!(names.contains("file3.txt"));
    }

    #[test]
    fn test_collect_files_empty_directory() {
        let tmpdir = tempfile::tempdir().unwrap();

        let mut files: Vec<std::path::PathBuf> = Vec::new();
        UnifiedGitBackend::collect_files(tmpdir.path(), &mut files).unwrap();
        assert!(files.is_empty());
    }
}

