/// Check if `basename` starts with any of the given prefixes.
/// The prefix must be followed by a period, underscore, or end-of-string
/// to avoid matching things like "security-group" when checking "security".
fn metadata_basename_prefix<'a>(
    basename: &str,
    prefixes: &'a [&'a str],
) -> bool {
    prefixes
        .iter()
        .any(|p| {
            if !basename.starts_with(p) {
                return false;
            }
            // Exact match or next char must be '.' or '_' (not a word boundary
            // like '-' or space)
            let rest = &basename[p.len()..];
            rest.is_empty() || matches!(rest.chars().next(), Some('.' | '_'))
        })
}

